import{_ as e,a as t,b as r,c as n,d as l}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as d}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as i,o,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Other/ocr.md","filePath":"tr-TR/Other/ocr.md","lastUpdated":1781962217000}'),u={name:"tr-TR/Other/ocr.md"};function m(p,a,k,g,h,y){return o(),s("div",null,[...a[0]||(a[0]=[c('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR; görsellerden, taramalardan ve belge ekran görüntülerinden metin çıkarır.</p><p>Tanıma tamamlandıktan sonra sonucu kopyalayabilir, <code>Markdown</code>, <code>PDF</code> veya <code>Word</code> olarak dışa aktarabilir ya da birden fazla formatı birlikte paketleyip indirebilirsiniz.</p><h2 id="ocr-neler-yapabilir" tabindex="-1">OCR Neler Yapabilir? <a class="header-anchor" href="#ocr-neler-yapabilir" aria-label="Permalink to &quot;OCR Neler Yapabilir?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Özellik</th><th>Açıklama</th></tr></thead><tbody><tr><td>Görsel metin tanıma</td><td>Görsellerden, ekran görüntülerinden ve taramalardan metin çıkarır.</td></tr><tr><td>Belge düzeni tanıma</td><td>Tablolar, formüller, damgalar ve karma metin-görsel düzenler için daha uygundur.</td></tr><tr><td>Birden fazla servis</td><td>Baidu PaddleOCR, Microsoft Azure Vision ve Google Vision destekler.</td></tr><tr><td>Sonuçları kopyalama</td><td>İşlemden sonra tanınan metni kopyalar.</td></tr><tr><td>Dosya dışa aktarma</td><td><code>Markdown</code>, <code>PDF</code> ve <code>Word</code> dışa aktarır.</td></tr><tr><td>Batch packaging</td><td>Birden fazla dosya tanındıktan sonra sonuçları paket halinde indirir.</td></tr></tbody></table><h2 id="once-ocr-servislerini-yapılandırın" tabindex="-1">Önce OCR Servislerini Yapılandırın <a class="header-anchor" href="#once-ocr-servislerini-yapılandırın" aria-label="Permalink to &quot;Önce OCR Servislerini Yapılandırın&quot;">​</a></h2><p>Şurayı açın:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP geolocation ve OCR" loading="lazy"></p><p>Kullanmak istediğiniz servisler için credentials değerlerini doldurun:</p><table tabindex="0"><thead><tr><th>Servis</th><th>Ne girilir</th><th>En uygun kullanım</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>İlk tercih olarak önerilir. Belgeler, görseller, tablolar ve karma düzenler için iyidir.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> ve <code>Azure Vision API Key</code></td><td>Microsoft bulut servislerini zaten kullanıyorsanız yararlıdır.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> yalnızca kota sorgusu için kullanılır.</td><td>Google Cloud servisleri kullanıyorsanız yararlıdır.</td></tr></tbody></table><p>Credentials girdikten sonra kaydedin.</p><p>İlk test için yalnızca bir servis yapılandırabilirsiniz. Üçünün de gerekli olması şart değildir.</p><h2 id="google-vision-kurulumu" tabindex="-1">Google Vision Kurulumu <a class="header-anchor" href="#google-vision-kurulumu" aria-label="Permalink to &quot;Google Vision Kurulumu&quot;">​</a></h2><p>Google kurulumu iki parçadan oluşur:</p><table tabindex="0"><thead><tr><th>Amaç</th><th>Gereken</th></tr></thead><tbody><tr><td>OCR kullanmak</td><td><code>Cloud Vision API</code> etkinleştirip <code>API Key</code> oluşturmak.</td></tr><tr><td>Kullanımı sorgulamak</td><td>Service account oluşturmak, <code>Monitoring Viewer</code> vermek ve service account <code>JSON</code> indirmek.</td></tr></tbody></table><p><img src="'+d+'" alt="Google API key ve service account" loading="lazy"></p><h3 id="ocr-icin-google-kullanma" tabindex="-1">OCR İçin Google Kullanma <a class="header-anchor" href="#ocr-icin-google-kullanma" aria-label="Permalink to &quot;OCR İçin Google Kullanma&quot;">​</a></h3><ol><li>Google Cloud Console&#39;u açın.</li><li><code>APIs &amp; Services</code> bölümüne gidin.</li><li><code>Library</code> açın, <code>Cloud Vision API</code> araması yapın ve etkinleştirin.</li><li><code>Credentials</code> bölümüne dönün.</li><li><code>API Key</code> oluşturun.</li><li>API Key&#39;i açıp kopyalayın.</li><li>ImgBed&#39;deki <code>Google Vision API Key</code> alanına yapıştırın.</li><li>Kaydedin.</li></ol><p>Ardından OCR penceresinde Google Vision seçebilirsiniz.</p><h3 id="google-kullanımını-sorgulama" tabindex="-1">Google Kullanımını Sorgulama <a class="header-anchor" href="#google-kullanımını-sorgulama" aria-label="Permalink to &quot;Google Kullanımını Sorgulama&quot;">​</a></h3><p>Quota query tanıma işlemi için gerekli değildir.</p><p>Yalnızca son 30 günde yaklaşık kaç Google Vision çağrısı kullanıldığını gösterir.</p><ol><li>Google Cloud Console&#39;da <code>IAM &amp; Admin</code> bölümünü açın.</li><li><code>Service Accounts</code> bölümünü açın.</li><li><code>vision-monitor</code> gibi bir service account oluşturun.</li><li><code>Monitoring Viewer</code> rolünü verin.</li><li>Service account ayrıntılarını açın ve key oluşturun.</li><li><code>JSON</code> seçin.</li><li>Oluşturulan JSON dosyasını indirin.</li><li>ImgBed&#39;e dönün ve service account <code>JSON</code> altında içe aktarın (isteğe bağlı).</li><li>İçe aktarma başarılı olduktan sonra quota query tıklayın.</li></ol><p>İçe aktardıktan sonra ImgBed service account sahibi project name değerini gösterir. Kullanım sorgulanırken ImgBed Google monitoring data okur ve bu ayın çağrı sayısını gösterir.</p><p>Kısaca:</p><table tabindex="0"><thead><tr><th>Öğe</th><th>Amaç</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>OCR tanıma yapar.</td></tr><tr><td>Service account <code>JSON</code></td><td>Kaç Google Vision çağrısı kullanıldığını sorgular.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>Service account&#39;un usage data okumasını sağlar.</td></tr></tbody></table><h2 id="baidu-paddleocr-token-alma" tabindex="-1">Baidu PaddleOCR Token Alma <a class="header-anchor" href="#baidu-paddleocr-token-alma" aria-label="Permalink to &quot;Baidu PaddleOCR Token Alma&quot;">​</a></h2><p>Baidu PaddleOCR access token ister.</p><p><img src="'+t+'" alt="PaddleOCR token alma" loading="lazy"></p><p>Baidu PaddleOCR sayfasındaki <code>API</code> çağrı penceresini açın, token alma düğmesine tıklayın ve kopyalayın.</p><p>ImgBed&#39;e dönün, <code>PaddleOCR Token</code> alanına yapıştırın ve kaydedin.</p><h2 id="tanımayı-baslatma" tabindex="-1">Tanımayı Başlatma <a class="header-anchor" href="#tanımayı-baslatma" aria-label="Permalink to &quot;Tanımayı Başlatma&quot;">​</a></h2><p>File Management içinde bir görsel veya belge ekran görüntüsü seçin ve <code>OCR</code> tıklayın.</p><p><img src="'+r+'" alt="OCR tanıma" loading="lazy"></p><p>Pencerede tanıma servisini ve modeli seçin.</p><p>Yaygın PaddleOCR model seçenekleri:</p><table tabindex="0"><thead><tr><th>Model</th><th>En uygun kullanım</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Varsayılan olarak önerilir. Belgeler, tablolar, formüller, damgalar ve karma düzenler için iyidir.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Basit görseller, sıradan metinler ve hafif tanıma.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Çok dilli, karmaşık görseller ve chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Daha karmaşık belge sayfaları ve layout recovery.</td></tr></tbody></table><p>Emin değilseniz <code>PP-StructureV3</code> ile başlayın.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seçenek</th><th>Açıklama</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Görsel döndürülmüş veya eğikse kullanın.</td></tr><tr><td>Document flattening</td><td>Eğrilik veya açı içeren fotoğraflanmış belgeler için.</td></tr><tr><td>Layout detection</td><td>Başlık, paragraf, tablo ve görsel yapısını korumak istediğinizde.</td></tr><tr><td>Chart recognition</td><td>Görselde grafik veya karmaşık yapı varsa.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Dışa aktarılan Markdown&#39;u daha okunur yapar.</td></tr></tbody></table><p>Normal ekran görüntülerinde seçenekleri az tutun. Belge taramalarında daha fazla belge odaklı seçeneği etkinleştirin.</p><h2 id="sonucları-goruntuleme" tabindex="-1">Sonuçları Görüntüleme <a class="header-anchor" href="#sonucları-goruntuleme" aria-label="Permalink to &quot;Sonuçları Görüntüleme&quot;">​</a></h2><p>Tanıma bittiğinde pencere sonucu gösterir.</p><p>Doğrudan kopyalayabilir veya dışa aktarma formatlarını seçebilirsiniz.</p><p><img src="'+n+'" alt="PDF tanıma" loading="lazy"></p><p>Belge sayfalarında dışa aktarılan <code>PDF</code>, sayfa görünümünü korurken metni aranabilir tutabilir. Taramaları arşivlemek ve daha sonra içerik aramak için kullanışlıdır.</p><h2 id="dısa-aktarma-formatı-secimi" tabindex="-1">Dışa Aktarma Formatı Seçimi <a class="header-anchor" href="#dısa-aktarma-formatı-secimi" aria-label="Permalink to &quot;Dışa Aktarma Formatı Seçimi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>En uygun kullanım</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notlar, dokümantasyon sistemleri ve sonraki düzenleme.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Sayfa görünümünü ve taranmış belge sonucunu koruma.</td></tr><tr><td><code>Word (.docx)</code></td><td>Düzeni düzenlemeye devam etme, metin değişikliği ve başkalarına aktarma.</td></tr><tr><td>Export all</td><td>Birden fazla formatı ve özgün görseli kaydeder; önemli arşivler için uygundur.</td></tr></tbody></table><p>Yalnızca metne ihtiyacınız varsa Markdown dışa aktarın.</p><p>Sayfa görünümü önemliyse PDF veya Word kullanın.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Dışa aktarılan Word belgeleri office yazılımlarında açılıp düzenlenebilir.</p><p><img src="'+l+`" alt="Word sonucu" loading="lazy"></p><p>Bazı belgeler Word output içinde tanınan görseller, başlıklar ve paragraflar içerebilir.</p><p>Tanıma kalitesi özgün görsel netliğine, model seçimine ve belge karmaşıklığına bağlıdır.</p><h2 id="ocr-icin-en-uygun-dosya-turleri" tabindex="-1">OCR İçin En Uygun Dosya Türleri <a class="header-anchor" href="#ocr-icin-en-uygun-dosya-turleri" aria-label="Permalink to &quot;OCR İçin En Uygun Dosya Türleri&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dosya Türü</th><th>Öneri</th></tr></thead><tbody><tr><td>Net ekran görüntüleri</td><td>Doğrudan tanıyın.</td></tr><tr><td>Taramalar</td><td><code>PP-StructureV3</code> tercih edin.</td></tr><tr><td>Fotoğraflanmış belgeler</td><td>Orientation correction ve document flattening etkinleştirin.</td></tr><tr><td>Tablolar, formüller, damgalar</td><td>Structured models tercih edin.</td></tr><tr><td>Basit kısa metin görselleri</td><td><code>PP-OCRv5</code> genellikle yeterlidir.</td></tr></tbody></table><p>Daha net ve daha düz metinli görseller genellikle daha iyi sonuç verir.</p><h2 id="yaygın-durumlar" tabindex="-1">Yaygın Durumlar <a class="header-anchor" href="#yaygın-durumlar" aria-label="Permalink to &quot;Yaygın Durumlar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Durum</th><th>Anlamı</th></tr></thead><tbody><tr><td>Recognition fails</td><td>Service token veya key kaydedildi mi kontrol edin.</td></tr><tr><td>Recognition is slow</td><td>Karmaşık belgeler ve büyük görseller daha uzun sürer.</td></tr><tr><td>Table is incomplete</td><td>Structured model deneyin.</td></tr><tr><td>Text has mistakes</td><td>Bulanıklık, parlama ve eğiklik hataları artırır. Daha net görsel deneyin.</td></tr><tr><td>Word output contains many images</td><td>Structured models tanınan bazı görselleri koruyabilir. Bu normaldir.</td></tr></tbody></table><h3 id="google-quota-query-fails" tabindex="-1">Google Quota Query Fails <a class="header-anchor" href="#google-quota-query-fails" aria-label="Permalink to &quot;Google Quota Query Fails&quot;">​</a></h3><p>Kontrol edin:</p><ol><li>Service account <code>JSON</code> içe aktarıldı.</li><li>Service account <code>Monitoring Viewer</code> rolüne sahip.</li><li>Projede <code>Cloud Vision API</code> etkin.</li></ol><p>Yalnızca OCR gerekiyorsa ve usage query gerekmiyorsa service account JSON kullanmayabilir, yalnızca <code>Google Vision API Key</code> doldurabilirsiniz.</p><h2 id="kısa-akıs" tabindex="-1">Kısa Akış <a class="header-anchor" href="#kısa-akıs" aria-label="Permalink to &quot;Kısa Akış&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings aç</span></span>
<span class="line"><span>-&gt; Other Settings aç</span></span>
<span class="line"><span>-&gt; OCR service credentials doldur</span></span>
<span class="line"><span>-&gt; Kaydet</span></span>
<span class="line"><span>-&gt; File Management&#39;a dön</span></span>
<span class="line"><span>-&gt; Dosya seç ve OCR tıkla</span></span>
<span class="line"><span>-&gt; Model seç</span></span>
<span class="line"><span>-&gt; Tanımayı bekle</span></span>
<span class="line"><span>-&gt; Sonuçları kopyala veya Markdown / PDF / Word dışa aktar</span></span></code></pre></div>`,67)])])}const O=i(u,[["render",m]]);export{f as __pageData,O as default};
